import{_ as s,o as t,c as i,ag as r}from"./chunks/framework.ETe_P6d1.js";const _="/kaiping-reports/assets/1.D0uq8yLt.jpg",a="/kaiping-reports/assets/2.CIrfGacs.jpg",o="/kaiping-reports/assets/3.z2O2VeV_.jpg",e="/kaiping-reports/assets/4.Og5M4OIf.jpg",l="/kaiping-reports/assets/5.B3FyFQte.jpg",n="/kaiping-reports/assets/6.BOLJwEEA.jpg",g="/kaiping-reports/assets/7.CdcY2jzg.jpg",c="/kaiping-reports/assets/8.B_5JFP-V.jpg",m="/kaiping-reports/assets/9.BnY0WqfR.jpg",k="/kaiping-reports/assets/10.C2dRVtSp.jpg",d="/kaiping-reports/assets/11.Dc2B4Tkl.jpg",j="/kaiping-reports/assets/12.DXMY7IaJ.jpg",f="/kaiping-reports/assets/13.CjWPnu-Z.jpg",u="/kaiping-reports/assets/14.BQGZFLae.jpg",h="/kaiping-reports/assets/15.DiBCdENp.jpg",C="/kaiping-reports/assets/16.DmC5_QzC.jpg",B="/kaiping-reports/assets/17.Cmv5k2XC.jpg",x=JSON.parse('{"title":"《立园与仓东村建筑对比研究：从全球物质流动到地方感官秩序的建构》","description":"","frontmatter":{"title":"《立园与仓东村建筑对比研究：从全球物质流动到地方感官秩序的建构》"},"headers":[],"relativePath":"reports/姚柯羽/姚柯羽 《立园与仓东村建筑对比研究：从全球物质流动到地方感官秩序的建构》调研报告.md","filePath":"reports/姚柯羽/姚柯羽 《立园与仓东村建筑对比研究：从全球物质流动到地方感官秩序的建构》调研报告.md"}'),P={name:"reports/姚柯羽/姚柯羽 《立园与仓东村建筑对比研究：从全球物质流动到地方感官秩序的建构》调研报告.md"};function D(T,p,V,q,M,S){return t(),i("div",null,[...p[0]||(p[0]=[r('<h1 id="《立园与仓东村建筑对比研究-从全球物质流动到地方感官秩序的建构》" tabindex="-1">《立园与仓东村建筑对比研究：从全球物质流动到地方感官秩序的建构》 <a class="header-anchor" href="#《立园与仓东村建筑对比研究-从全球物质流动到地方感官秩序的建构》" aria-label="Permalink to &quot;《立园与仓东村建筑对比研究：从全球物质流动到地方感官秩序的建构》&quot;">​</a></h1><h1 id="作者-调研团队" tabindex="-1">作者：调研团队 <a class="header-anchor" href="#作者-调研团队" aria-label="Permalink to &quot;作者：调研团队&quot;">​</a></h1><p>考察地点及选取理由</p><p>本次调研选取广东省开平市两处核心地点：</p><ol><li><p>立园：旅美华侨谢维立家族的私家园林（1926-1936年建）。</p></li><li><p>仓东村：谢氏宗族传统村落，为立园主人的祖籍地。</p></li></ol><p>选取此二处进行对比研究，基于其构成的一组极具阐释力的二元关系：</p><ol><li><p>“极”与“常”的类型对照：立园代表侨乡建筑中个人意志、雄厚资本与艺术追求的极致表达，是精心设计的“文化纪念碑”；仓东村则代表侨乡社会宗族集体、普遍实践与日常生活的普遍呈现，是自然生长的“生活容器”。二者恰好构成侨乡建筑谱系上“艺术极”与“生活常”的两端。</p></li><li><p>“同源异流”的深度关联：两地地缘相邻、血缘同宗，同属塘口镇谢氏家族。这使得对比超越了风格罗列，能深入揭示：在同一文化母体中，因建造主体（个人 vs 宗族）与核心意图（彰显 vs 实用）的根本不同，如何导致了材料技术、形式策略与文化表达的系统性分化。</p></li><li><p>研究维度的天然互补：立园是分析钢筋混凝土技术、园林空间营造、高等级装饰艺术的绝佳个案。仓东村是研究村落整体格局、祠校碉楼等多类型建筑、社会防御与教化功能的综合样本。二者结合，能从微观技艺到宏观结构，从个人情志到集体逻辑，完整解读“中西合璧”的多元实现机制。</p></li></ol><p>一、引言：两种“侨”之根的物质形态</p><p>在开平侨乡的建筑群中，立园与仓东村呈现出一组极具深意的对照。它们同属谢氏家族的文化脉络，却因空间属性、社会功能与建造意图的根本差异，在相同的“中西合璧”旗帜下，发展出两套截然不同的建筑语言体系。立园是一座内向的、高度个人化的私家园林综合体，是其创建者谢维立个人财富、审美与家族观念的终极物质结晶；而仓东村则是一个外向的、承载宗族集体记忆的传统村落，是谢氏宗族数百年繁衍、并在近代华侨资本反哺下形成的公共生活空间。本报告将从建造材料与构造与装饰符号与文化表达两个核心维度，对二者进行系统性比对，旨在揭示侨乡建筑实践中，因私与公，个人和宗族的差异所体现出不同的建筑语言。</p><p>二、建造材料与构造：精工定制与务实改良的并置</p><p>1.1 钢筋混凝土：形式自由的物质前提</p><p>在立园中，以泮立楼、泮文楼为代表的主体别墅，采用了当时先进的钢筋混凝土框架结构，其结构选择具有强烈的实验性与象征性。这一技术选择不仅是出于坚固性或防御性的实用考虑，更关键的是，它为一系列突破传统的空间与形式实验提供了结构可能性。</p><p>现场观察可见，钢筋混凝土框架使得建筑能够实现大跨度开间、悬挑阳台与宽阔外廊。在泮文楼和泮立楼中，外廊进深可达2.5米，由纤细的方形钢筋混凝土柱支撑。</p><p><img src="'+_+'" alt="图1"></p><p><img src="'+a+'" alt="图2"></p><p>这些拱券（多为半圆形或弧形）并非砖石砌筑，而是与罗马柱、楼板整体现浇的钢筋混凝土构件。施工时需架设精密的弧形木模板，绑扎钢筋后浇筑混凝土。这种构造使拱券成为刚性框架的一部分，能够实现大跨度的连续开敞立面，为西式敞廊提供了物质基础（图1，2）。</p><p>而立园的罗马柱作为园内中西融合典型象征之一也同时体现了现代建筑技术和新材料结合的革新。其钢筋混凝土框架不仅是技术的选择，更是资本全球化网络的物质终点。不同的材料源自不同的国家，这种材料的全球流动，构建了一个与地方建筑传统平行的、私人的、外向型的技术体系。框架结构带来的空间解放——大跨度、悬挑阳台、连续拱窗都是对西方现代生活“敞亮”、“通透”理念的技术回应。</p><p><img src="'+o+'" alt="图3"></p><p>反观仓东村，其建筑（祠堂与碉楼）在结构上则更体现 “务实改良” 与 “功能优先”。以秉文谢公祠为例，其主体采用了砖木与钢筋混凝土的混合结构：承重外墙为传统青砖砌筑（图3），但内部梁架已使用来自西方的水泥钢筋，同时结合了来自南洋的坤甸木桁条以抵御潮湿。这种结构并非对西方框架体系的完整模仿，而是在传统营造体系基础上，对关键部位进行现代化加固。其标志性的西式立面（拱券、柱式）更多是装饰性的表皮，附着在传统的空间格局之上。碉楼“焕业楼”虽全楼使用水泥、砂、石子和钢材建成，极为坚固，但其厚墙小窗、垂直筒状的空间形态，完全服务于防御功能，是功能主义导向下的技术应用，而非文化展示（图4）。</p><p><img src="'+e+'" alt="图4"></p><p><img src="'+l+'" alt="图5"></p><p>而在宝树楼中，也有一个极具功能和代表性的细节展现，其屋顶并非完全封闭，而是在女儿墙与瓦顶之间，或在硬山墙顶部，刻意留有规律性的通风缝隙。这种构造并非施工粗陋，而是一种针对岭南湿热多风气候的主动设计。缝隙允许台风期的强风穿透，有效降低屋面对风的直接阻力，避免瓦片被掀翻或结构受损；同时，在平日利于阁楼通风散热，防止木构架霉变。这体现了侨乡工匠在吸收外来形式的同时，对本土环境与材料性能的深刻理解和创造性应用。</p><p><img src="'+n+'" alt="图6"></p><p>1.2 材料应用：全球采购与在地转化</p><p>在材料的选择与组合上，两地差异显著。</p><p>立园宛如一个全球顶级建材的博览会。其材料谱系高度国际化且等级分明：主体结构用英国水泥、德国钢；装饰面层用意大利水磨石、瓷砖；屋顶用皇家规格的琉璃瓦等（图6）。这些材料通过谢维立私人开凿的运河，从全球网络直接输送至建造现场。其应用逻辑是旨在用最顶级的物质材料，实现最完美的文化意象与最摩登的生活品质。意大利水磨石地面通过复杂工艺在现场浇筑出永久性的华丽图案，其材料与工艺本身即是炫耀性资本。</p><p><img src="'+g+'" alt="图7"></p><p>仓东村则更多体现了 “在地化、实用化” 的特征。其主体材料仍是本地生产的青砖、木材、石材（图7）。进口材料作为关键部位的强化或功能性补充出现。例如，在祠堂梁架中使用水泥钢筋增强耐久性，在碉楼墙体中使用“红毛泥”提升防御力。这种应用是选择性的、问题导向的，目的在于以合理的成本提升建筑的安全性、耐久性与实用性，而非追求极致的物质表现或审美新奇。</p><p><img src="'+c+'" alt="图8"></p><p>三、装饰符号与文化表达：个人宣言与集体叙事的差异</p><p>在装饰符号的运用上，立园是一场由园主主导的、充满个人趣味的“文化独白”；而仓东村则是一场由宗族集体书写、面向子孙与社群的“公共叙事”。</p><p>2.1 中西融合的策略：深度象征与功能并置</p><p>立园的中西融合追求一种深度的、结构性的并置，并试图建立内在的象征秩序。其最经典的范式是“西柱中顶”，这不仅是形式的拼贴，更被赋予“西技载中道”的哲学隐喻——用西方的现代技术，托举东方的传统精神。在室内，西式壁炉与潮州金漆木雕、意大利瓷砖与中式壁画并置（图8），是两种文化核心审美与生活方式的直接对话与竞争。这种融合带有强烈的个人意志与叙事性，是园主谢维立内心文化认同冲突、调和与终极理想的外化。</p><p><img src="'+m+'" alt="图9"></p><p>立园的装饰题材具有鲜明的精英艺术品味与个人生命隐喻。灰塑、壁画题材多源于历史典故与古典文学，承载着园主的文人雅趣与人生理想。园林中的鸟巢、花藤亭等建筑，更是充满个人情感与命运象征的独特创造（图9）。</p><p><img src="'+k+'" alt="图10"></p><p>仓东村的中西融合则更倾向于表层的、功能导向的拼贴，服务于明确的公共与教育功能。以秉文谢公祠为例，其立面采用了柯林斯柱式大跨拱券、爱奥尼柱式等西式元素，但楼顶山花却采用中国传统灰雕工艺，镶嵌神兽、卷草、人物故事（图10，11）。这种组合并非追求深层的哲学隐喻，其核心逻辑是标识与教化：西式立面彰显家族的国际视野与财力，为作为学校的建筑注入现代气息；传统灰雕则时刻提醒学子不忘根本与孝道。在壁画题材上，既有传统的凤凰、麒麟、人物故事，也出现了洋楼、轮船、探照灯等现代事物，直观反映了侨乡民众“保守本土文化”与“憧憬现代生活”的并存心态，这是一种大众化的、面向现实的文化表达。</p><p>仓东村的装饰题材则洋溢着世俗的伦理教化与宗族集体记忆。祠堂内，“恪守族训，宏大德门”的石刻对联直接点明核心价值（图12）。堂上陈列的祖先牌位与“人群竞进、家族开明”的楹联，共同承载着落叶归根的宗族情怀与在中西交融下开明进取的家族理念。装饰题材直接服务于宗族凝聚力建设、后代教育以及对华侨贡献的纪念，是集体意志与世俗精神的直观反映。</p><p><img src="'+d+'" alt="图11"></p><p><img src="'+j+'" alt="图12"></p><p><img src="'+f+'" alt="图13"></p><p>2.2 材料与构造的本色与文化的赋色</p><p>在色彩体系与空间氛围上，两地也迥然不同。</p><p>立园的建筑群以青砖灰、米黄墙、琉璃绿构成了统一而典雅的基调，室内则用金色、彩绘、彩色玻璃进行华丽点缀。其空间通过运河、回廊、桥亭的连接，形成“园中有园，景中有景”的深幽意境。这是一种有计划的、自上而下的审美统治，旨在营造一个超越现实、诗意栖居的乌托邦。</p><p>而在内部空间中，平面和立面的材料也装点着不同的色彩，意大利水磨石地坪的光洁、坚硬、凉爽触感，与室外土地的粗粝、湿润形成尖锐的感官对比。虽然图案复杂，但其基础仍建立在规整的网格上。实测常见单块色块区域的边长在30厘米至50厘米之间。在泮立楼大厅地面，仔细观察可发现其弯折也非常流畅，接缝严密，这说明工匠在弹线、镶嵌时具有极高的精度。</p><p><img src="'+u+'" alt="图14"></p><p>当我们将视线聚焦于头顶的一方天地，立园文化表达的精密与深邃，反而在泮立楼的天花板装饰上获得了最为浓缩的呈现。</p><p>该天花板并非传统木构架，而是一个清晰的现代吊顶系统。其基础是由简洁的白色石膏板或灰浆板构成的平面吊顶，在此基底上，通过精密计算，嵌入了标准化的装饰单元。</p><p>每个方形装饰单元尺寸一致，其外缘金色边框宽度均等，表明生产时采用了标准化模具。单元之间的间距严格相等，形成了强烈的网格秩序感。这种构造方式，与立园外墙的预制混凝土花格窗、水磨石地坪的分格逻辑一脉相承，体现了20世纪初工业化、模数化的建造思想对传统装饰工艺的改造。</p><p><img src="'+h+'" alt="图15"></p><p>立园室内的色彩在此展现出最大的叛逆与张扬，完全跳脱了外部的中庸与典雅。从具体颜色上来看主要分为两种，亮粉与明黄色相间，亮粉与蓝绿色相间，其以严格的马赛克图案铺贴。这种铺贴方式对施工精度要求极高，需确保每一行、每一列的颜色对齐，勾缝均匀。它产生的是一种无限延伸的、充满动感的视觉网格，是装饰艺术风格的典型手法。它们不追求含蓄、调和，而是追求即刻的、强烈的视觉刺激和情绪唤醒。</p><p>这种美学，并非源自中国古典或西方古典传统，而更接近20世纪初流行于国际商业空间、娱乐场所及中产阶级家庭的 “摩登”审美。它物化了华侨对“现代生活”的想象：明亮的、卫生的、愉悦的、脱离乡土灰调感的。色彩本身，就是的最直接符号，更像一种感官层面的现代性宣言。</p><p><img src="'+C+'" alt="图16"></p><p><img src="'+B+'" alt="图17"></p><p>仓东村的色彩与空间则是自然生长的生活现场。村落依山面水，榕树竹林点翠，充满岭南传统村落的风水格局与生活气息。建筑材质（青砖、红砖、抹灰）本身形成朴素的色彩变化。祠堂与碉楼并立于村落肌理中，与传统的三间两廊民居、夫人庙、忠心社等共同构成一幅完整的、持续演进的侨乡生活画卷。色彩与空间在这里是自发的、功能性的、与日常生活紧密相连的，没有统一的视觉规划，却在宗族组织与实用需求下形成了独特的、充满生命力的村落美学。混凝土的“灰”与木构的“褐”。作为四层混凝土建筑，其楼板、墙体、柱体很可能保留水泥砂浆抹面的青灰色或灰白色，呈现出工业材料的质朴与坚固感。而天井后的礼堂采用“木梁盖青瓦”，则引入了木材的原褐色与瓦片的青灰色，在冰冷的混凝土体中嵌入了一方温润的传统木构空间。</p><p>四、批判性反思与结论</p><p>通过对立园与仓东村的系统性对比，我们在赞叹其建筑智慧与美学成就的同时，也必须以批判性的眼光审视其“中西合璧”实践背后所隐含的张力、矛盾与历史局限性。立园的实践清晰地展示了一种悖论：它采用了当时最先进的结构技术（钢筋混凝土框架），却用其服务于最为保守的文化表达形式（古典柱式、中式大屋顶）。这并非指向未来的建筑实验，而更像是一种用新材料“复刻”的、理想化的过去与异域的结合体。这种“技术先行，形式怀旧”的模式，暴露了早期现代化进程中常见的文化滞后与身份焦虑。建造者急切地拥抱代表“进步”的技术，却尚未找到或不愿放弃能够承载自身文化认同的崭新形式语言，最终折衷为一种象征性的拼贴。在仓东村，这种悖论则以另一种形式出现：现代材料（水泥）被用于加固和装饰传统的宗族空间（祠堂），其结果是强化了传统的社会结构与价值观，而非催生新的空间伦理。技术在此成为了传统的增强剂而非革新者。</p><p>五、结论</p><p>立园与仓东村的对比，揭示了中国近代建筑现代化进程中两条并行的路径，它们共同构成了理解“中西合璧”这一复杂现象的钥匙。</p><p>立园代表了一种 “精英主导的乌托邦式融合” 。它以雄厚的资本为后盾，通过系统的规划、先进的技术和精心的设计，试图创造一个融合中西、超越现实的理想家园。其本质是个人意志与文化野心的纪念碑，是谢维立个人对“现代性”与“传统”关系的诗意解答。它精致、完整，但也因其强烈的个人色彩与实验性而略显孤独。</p><p>仓东村则代表了一种 “社群驱动的实用主义融合” 。它根植于宗族社会的集体需求，以解决实际问题（防御、居住、教化）为导向，对外来技术与形式进行选择性吸收和本土化改造。其本质是社群生存智慧与集体身份认同的容器。它质朴、混杂，却充满了生活的温度与历史的韧性，是侨乡社会应对时代剧变的真实写照。</p><p>两者殊途同归，都体现了第一代华侨在跨文化语境中，试图用建筑锚定自身身份、表达文化归属、构建理想生活的强烈愿望。它们的价值不仅在于独特的建筑形式，更在于其作为文化接触、碰撞与调适的“物质性文本”。它们告诉我们，文化的融合从来不是单向的接受或取代，而是一个充满协商、转化与创造的动态过程。</p><p>六、附录：调研记录</p><p>6.1 摄影记录</p><p>本报告共插入17张现场照片，分别展示：</p><ul><li>图1-图3：立园建筑外观与细部装饰</li><li>图4-图6：仓东村建筑构造</li><li>图7-图8：立园和仓东村的材料利用差异</li><li>图9-图13：立园和仓东村装饰题材差异</li><li>图14-图17：立园和仓东村建筑细节用色体现</li></ul><p>6.2 文献资料</p><p>[1] 程建军《开平碉楼——中西合璧的侨乡文化景观》[M]. 北京：中国建筑工业出版社，2007.</p><p>[2] 谭金花《开平碉楼与村落的建筑装饰研究》[M]. 北京：中国华侨出版社，2013.</p><p>[3] 钱毅《近代乡土建设-开平碉楼》[M]. 北京：中国林业出版社，2015.</p><p>[4] 黎捷《开平碉楼与村落》[M]. 北京：人民出版社，2024.</p>',71)])])}const E=s(P,[["render",D]]);export{x as __pageData,E as default};
